DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "parserMultiAnswer.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
Context('Numeric');
do {
  $a = random(1,10,1);
  $b = random(-10,-1,1);
  $c = random(1,10,1);
  $exponent = $a + $b - $c;
} until ($exponent > 5);
$multians = MultiAnswer($a, $b, $c)->with(
singleResult => 1,
  checker => sub {
    my ( $correct, $student, $self ) = @_;
    my ( $astu, $bstu, $cstu ) = @{$student};
    my ( $acor, $bcor, $ccor ) = @{$correct};
    if ( $astu <= 0) {Value::Error('Your value for a should be positive.')};
    if ( $bstu >= 0) {Value::Error('Your value for b should be negative.')};
    if ( $cstu <= 0) {Value::Error('Your value for c should be positive.')};
    if ($astu+$bstu-$cstu != $exponent) {return 0;} else {return 1};
  }
);
do {
  $d = random(1,10,1);
  $e = random(-10,-1,1);
  $f = random(1,10,1);
  $negexponent = $d + $e - $f;
} until ($negexponent < -5);
$multians2 = MultiAnswer($d, $e, $f)->with(
singleResult => 1,
  checker => sub {
    my ( $correct, $student, $self ) = @_;
    my ( $dstu, $estu, $fstu ) = @{$student};
    my ( $dcor, $ecor, $fcor ) = @{$correct};
    if ( $dstu <= 0) {Value::Error('Your value for a should be positive.')};
    if ( $estu >= 0) {Value::Error('Your value for b should be negative.')};
    if ( $fstu <= 0) {Value::Error('Your value for c should be positive.')};
    if ($dstu+$estu-$fstu != $negexponent) {return 0;} else {return 1};
  }
);
$abs = abs($negexponent);

############################################################
# Body
############################################################

BEGIN_PGML
Consider the expression [`\dfrac{x^a\cdot x^b}{x^c}`] where [`\newcommand{\lt}{<}\newcommand{\gt}{>}a\gt0, b\lt0\text{,}`] and [`\newcommand{\gt}{>}c \gt 0\text{.}`]
a.  Are there values for [`a\text{,}`] [`b\text{,}`] and [`c`] so that the expression equals [`x^{[$exponent]}\text{?}`] If so, fill in the blanks below with possible values for [`a\text{,}`] [`b\text{,}`] and [`c\text{.}`] If not, fill in the blanks below with the word [|none|]*.

    [`a`] = [_]{$multians}{10}, [`b`] = [_]{$multians}{10}, and [`c`] = [_]{$multians}{10}

a.  Are there values for [`a\text{,}`] [`b\text{,}`] and [`c`] so that the exponential expression equals [`\frac{1}{x^{[$abs]}}\text{?}`] If so, fill in the blanks below with possible values for [`a\text{,}`] [`b\text{,}`] and [`c\text{.}`] If not, fill in the blanks below with the word [|none|]*.

    [`a`] = [_]{$multians2}{10}, [`b`] = [_]{$multians2}{10}, and [`c`] = [_]{$multians2}{10}

END_PGML

############################################################
# Solution
############################################################

BEGIN_PGML_SOLUTION
a.  The problem states that [`\frac{x^a\cdot x^b}{x^c}=x^{[$exponent]}\text{.}`] To simplify [`\frac{x^a\cdot x^b}{x^c}\text{,}`] we must add the exponents [`a`] and [`b\text{,}`] and then subtract the exponent [`c\text{.}`] Thus, [`a+b-c`] must equal [`[$exponent]\text{.}`] For example, [`[$a]+{[$b]}-[$c]=[$exponent]\text{.}`]

a.  First off, we must remember that [`\frac{1}{x^{[$abs]}} = x^{[$negexponent]}\text{.}`] To simplify [` \frac {x^{a} \cdot x^{b}}{x^{c}}\text{,}`] we must add the exponents [`a`] and [`b\text{,}`] and then subtract the exponent [`c\text{.}`] Thus, [` a + b - c `] must equal [`[$negexponent]\text{.}`] For example, [`[$d] + {[$e]} - [$f] = [$negexponent]\text{.}`]

END_PGML_SOLUTION

